{
  "activities": [
    {
      "type": "activity",
      "title": "Studying the properties of acids and bases on reaction with indicators and metals",
      "unit_name": "Unit I: Chemical Substances - Nature and Behaviour",
      "chapter_name": "Chemical Reactions and Equations / Acids, Bases and Salts",
      "details": "Observe reactions of HCl and NaOH with litmus solution (blue/red), zinc metal, and solid sodium carbonate to identify properties."
    },
    {
      "type": "activity",
      "title": "Classifying chemical reactions through observation",
      "unit_name": "Unit I: Chemical Substances - Nature and Behaviour",
      "chapter_name": "Chemical Reactions and Equations",
      "details": "Perform and observe combination, decomposition, displacement, and double displacement reactions including action of water on quicklime and heat on ferrous sulphate crystals."
    },
    {
      "type": "activity",
      "title": "Determining reactivity series of metals",
      "unit_name": "Unit I: Chemical Substances - Nature and Behaviour",
      "chapter_name": "Metals and Non-metals",
      "details": "Observe the action of Zn, Fe, Cu, and Al on salt solutions (ZnSO4, FeSO4, CuSO4, Al2(SO4)3) to arrange metals in decreasing order of reactivity."
    },
    {
      "type": "activity",
      "title": "Comparative cleaning capacity of soap",
      "unit_name": "Unit I: Chemical Substances - Nature and Behaviour",
      "chapter_name": "Carbon and its Compounds",
      "details": "Study the cleaning capacity of a soap sample in soft water versus hard water."
    },
    {
      "type": "activity",
      "title": "Tracing light path through a glass slab",
      "unit_name": "Unit III: Natural Phenomena",
      "chapter_name": "Natural Phenomena",
      "details": "Trace the path of a ray of light passing through a rectangular glass slab for different angles of incidence and measure angles of incidence, refraction, and emergence."
    },
    {
      "type": "activity",
      "title": "Tracing light path through a prism",
      "unit_name": "Unit III: Natural Phenomena",
      "chapter_name": "Natural Phenomena",
      "details": "Trace the path of rays of light passing through a glass prism to observe refraction and dispersion."
    },
    {
      "type": "activity",
      "title": "Portfolio write-up on non-assessed topics",
      "unit_name": "Unit I, Unit II, Unit IV",
      "chapter_name": "Periodic Classification of Elements / Heredity and Evolution / Electric Effects",
      "details": "Prepare a brief write-up in the portfolio for topics included formatively (Periodic Classification, Heredity/Evolution, Electric Effects) to reinforce understanding without summative assessment."
    }
  ],
  "projects": [
    {
      "title": "Scientific Inquiry Plan Design",
      "unit_name": "Unit VIII: Nature of Science by Doing Science",
      "chapter_name": "Nature of Science by Doing Science",
      "details": "Design and implement a plan for scientific inquiry involving hypothesis formulation, variable identification, accurate instrument use, data representation in multiple modes, and communication of findings using scientific terminology."
    },
    {
      "title": "Case Study on Science in Human Life",
      "unit_name": "Unit V: Linkages between Scientific Knowledge and Other Curricular Areas",
      "chapter_name": "Linkages between Scientific Knowledge and Other Curricular Areas",
      "details": "Examine a case study related to the use of Science in human life from the perspective of Social Sciences and Ethics (e.g., Marie Curie, Jenner, green revolution, GMOs, conservation of biodiversity)."
    }
  ],
  "practicals": [
    {
      "title": "Finding pH of various samples",
      "unit_name": "Unit I: Chemical Substances - Nature and Behaviour",
      "chapter_name": "Acids, Bases and Salts",
      "details": "Find the pH of dilute Hydrochloric Acid, Dilute NaOH solution, Dilute Ethanoic Acid solution, Lemon juice, Water, and Dilute Hydrogen Carbonate solution using pH paper/universal indicator."
    },
    {
      "title": "Studying dependence of potential difference on current",
      "unit_name": "Unit IV: Effects of Current",
      "chapter_name": "Effects of Current",
      "details": "Study the dependence of potential difference (V) across a resistor on the current (I) passing through it, determine its resistance, and plot a graph between V and I."
    },
    {
      "title": "Determination of equivalent resistance",
      "unit_name": "Unit IV: Effects of Current",
      "chapter_name": "Effects of Current",
      "details": "Determine the equivalent resistance of two resistors when connected in series and parallel."
    },
    {
      "title": "Preparing temporary mount of leaf peel",
      "unit_name": "Unit II: World of Living",
      "chapter_name": "Life Processes / Reproduction",
      "details": "Prepare a temporary mount of a leaf peel to show stomata."
    },
    {
      "title": "Showing CO2 release during respiration",
      "unit_name": "Unit II: World of Living",
      "chapter_name": "Life Processes",
      "details": "Experimentally show that carbon dioxide is given out during respiration."
    },
    {
      "title": "Studying properties of acetic acid",
      "unit_name": "Unit I: Chemical Substances - Nature and Behaviour",
      "chapter_name": "Carbon and its Compounds",
      "details": "Study the odour, solubility in water, effect on litmus, and reaction with Sodium Hydrogen Carbonate of acetic acid (ethanoic acid)."
    },
    {
      "title": "Determination of focal length",
      "unit_name": "Unit III: Natural Phenomena",
      "chapter_name": "Natural Phenomena",
      "details": "Determine the focal length of a concave mirror and a convex lens by obtaining the image of a distant object."
    },
    {
      "title": "Studying binary fission and budding",
      "unit_name": "Unit II: World of Living",
      "chapter_name": "Reproduction",
      "details": "Study binary fission in Amoeba and budding in yeast and Hydra with the help of prepared slides."
    },
    {
      "title": "Identification of embryo parts",
      "unit_name": "Unit II: World of Living",
      "chapter_name": "Reproduction",
      "details": "Identify the different parts of an embryo of a dicot seed (pea, gram, or red kidney bean)."
    }
  ]
}
